#!/usr/bin/env python3\nimport paramiko\nimport time\n\nHOST = "168.119.79.238"\nPORT = 77\nUSERNAME = "sanliur"\nPASSWORD = "CHANGE_ME_CWP_SSH_PASSWORD"\n\ndef main():\n    ssh = paramiko.SSHClient()\n    ssh.set_missing_host_key_policy(paramiko.AutoAddPolicy())\n    ssh.connect(HOST, port=PORT, username=USERNAME, password=PASSWORD, \n                timeout=20, look_for_keys=False, allow_agent=False)\n    \n    channel = ssh.invoke_shell()\n    time.sleep(2)\n    \n    print("Creating Apache vhost for sanliurfa.com...")\n    \n    # Create vhost file line by line\n    vhost_lines = [\n        "<VirtualHost *:80>",\n        "    ServerName sanliurfa.com",\n        "    ServerAlias www.sanliurfa.com",\n        "    DocumentRoot /home/sanliur/public_html",\n        "    ",\n        "    ProxyPreserveHost On",\n        "    ProxyPass / http://127.0.0.1:4321/",\n        "    ProxyPassReverse / http://127.0.0.1:4321/",\n        "    ",\n        "    RewriteEngine On",\n        "    RewriteCond %{HTTP:Upgrade} websocket [NC]",\n        "    RewriteCond %{HTTP:Connection} upgrade [NC]",\n        '    RewriteRule ^/?(.*) "ws://127.0.0.1:4321/$1" [P,L]',\n        "    ",\n        "    <Directory /home/sanliur/public_html>",\n        "        Options -Indexes +FollowSymLinks",\n        "        AllowOverride All",\n        "        Require all granted",\n        "    </Directory>",\n        "    ",\n        "    ErrorLog /home/sanliur/public_html/logs/error.log",\n        "    CustomLog /home/sanliur/public_html/logs/access.log combined",\n        "</VirtualHost>",\n    ]\n    \n    channel.send("mkdir -p /home/sanliur/.conf/apache\n")\n    time.sleep(1)\n    \n    # Clear file first\n    channel.send("> /home/sanliur/.conf/apache/sanliurfa.com.conf\n")\n    time.sleep(1)\n    \n    for line in vhost_lines:\n        escaped = line.replace('"', '\\"')\n        channel.send(f'echo "{escaped}" >> /home/sanliur/.conf/apache/sanliurfa.com.conf\n')\n        time.sleep(0.2)\n    \n    # Verify\n    channel.send("cat /home/sanliur/.conf/apache/sanliurfa.com.conf\n")\n    time.sleep(2)\n    \n    output = ""\n    while channel.recv_ready():\n        output += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print("VHOST CONFIG:")\n    print(output[-600:])\n    \n    # Check if Apache can reload\n    channel.send("sudo /usr/local/apache/bin/apachectl configtest 2>&1\n")\n    time.sleep(3)\n    \n    output2 = ""\n    while channel.recv_ready():\n        output2 += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(0.5)\n    \n    print("\nAPACHE TEST:")\n    print(output2[-300:])\n    \n    channel.close()\n    ssh.close()\n\nif __name__ == "__main__":\n    main()\n
